            minorApiLevel = 1
        }
    }

    defaultConfig {
        applicationId = "com.southsouthwest.framelog"
        minSdk = 26
        targetSdk = 36
        versionCode = 1
        versionName = "1.0"

        testInstrumentationRunner = "androidx.test.runner.AndroidJUnitRunner"
    }

    buildTypes {
        release {
